import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import UsersPage from './pages/users/UsersPage';
import CoursPage from './pages/cours/CoursPage';
import ClubPage from './pages/club/ClubPage';
import FoyerPage from './pages/foyer/FoyerPage';
import BibliothequePage from './pages/bibliotheque/BibliothequePage';
import RestaurantPage from './pages/restaurant/RestaurantPage';

const titles = {
  '/': 'Dashboard',
  '/users': 'MS User',
  '/cours': 'MS Cours',
  '/club': 'MS Club',
  '/foyer': 'MS Foyer',
  '/bibliotheque': 'MS Bibliothèque',
  '/restaurant': 'MS Restaurant',
};

function Layout({ children }) {
  return (
    <div className="layout">
      <Sidebar />
      <main className="main">
        {children}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/users" element={<UsersPage />} />
          <Route path="/cours" element={<CoursPage />} />
          <Route path="/club" element={<ClubPage />} />
          <Route path="/foyer" element={<FoyerPage />} />
          <Route path="/bibliotheque" element={<BibliothequePage />} />
          <Route path="/restaurant" element={<RestaurantPage />} />
        </Routes>
      </Layout>
    </BrowserRouter>
  );
}
